/// <summary>
/// Data contract for the ETG DMS Revere Integration business event.
/// Holds primary key values, collection names, and data area context.
/// </summary>
[DataContract]
internal final class ETGDMSReverePurchAgreementIntegrationContract extends BusinessEventsContract
{
    str DealNumber;
    str DataAreaId;
    str OperationType;
    str ActivityName;
    str DocumentNumber;
    str DocumentDate;
    str ActivityOwner;
    str ActivityRemarks;
    str EffectiveDate;
    str AgreementId;

}

Method.Source:
